import{_ as e,a,b as t}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as o,o as l,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Aggiungere un canale Cloudflare R2","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/upload/cloudflare-r2.md","filePath":"it-IT/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"it-IT/upload/cloudflare-r2.md"};function c(u,i,s,g,p,m){return l(),r("div",null,[...i[0]||(i[0]=[d('<h1 id="aggiungere-un-canale-cloudflare-r2" tabindex="-1">Aggiungere un canale Cloudflare R2 <a class="header-anchor" href="#aggiungere-un-canale-cloudflare-r2" aria-label="Permalink to &quot;Aggiungere un canale Cloudflare R2&quot;">​</a></h1><h2 id="quando-usarlo" tabindex="-1">Quando usarlo <a class="header-anchor" href="#quando-usarlo" aria-label="Permalink to &quot;Quando usarlo&quot;">​</a></h2><p>Cloudflare R2 è una buona scelta se:</p><ul><li>ImgBed è già distribuito su Cloudflare e vuoi salvare i file in un bucket R2 dello stesso account.</li><li>Non vuoi configurare un endpoint S3 separato con access key e secret key.</li><li>Preferisci che lettura e scrittura passino dal binding R2 di Worker o Pages con una configurazione minima.</li></ul><p>In breve:</p><p>Il canale R2 non si crea manualmente nel pannello di amministrazione di ImgBed. Prima devi collegare un bucket R2 al progetto Cloudflare, usando esattamente <code>img_r2</code> come nome della variabile di binding.</p><h2 id="prima-di-iniziare" tabindex="-1">Prima di iniziare <a class="header-anchor" href="#prima-di-iniziare" aria-label="Permalink to &quot;Prima di iniziare&quot;">​</a></h2><ul><li>Un account Cloudflare.</li><li>Un bucket R2 già creato.</li><li>Permessi per gestire il progetto Cloudflare su cui è distribuito ImgBed.</li></ul><h2 id="configurazione-in-cloudflare" tabindex="-1">Configurazione in Cloudflare <a class="header-anchor" href="#configurazione-in-cloudflare" aria-label="Permalink to &quot;Configurazione in Cloudflare&quot;">​</a></h2><h3 id="_1-crea-un-bucket-r2" tabindex="-1">1. Crea un bucket R2 <a class="header-anchor" href="#_1-crea-un-bucket-r2" aria-label="Permalink to &quot;1. Crea un bucket R2&quot;">​</a></h3><ol><li>Accedi alla dashboard Cloudflare.</li><li>Apri <code>R2 Object Storage</code>.</li><li>Clicca su Create bucket.</li><li>Scegli un nome, per esempio <code>imgbed</code>.</li></ol><p>Questo bucket conterrà i file caricati.</p><p><img src="'+e+'" alt="Crea un bucket R2" loading="lazy"></p><h3 id="_2-collega-il-bucket-al-progetto-imgbed" tabindex="-1">2. Collega il bucket al progetto ImgBed <a class="header-anchor" href="#_2-collega-il-bucket-al-progetto-imgbed" aria-label="Permalink to &quot;2. Collega il bucket al progetto ImgBed&quot;">​</a></h3><p>Scegli il punto di binding in base al tipo di distribuzione:</p><table tabindex="0"><thead><tr><th>Tipo di distribuzione</th><th>Dove configurare il binding</th></tr></thead><tbody><tr><td>Pages</td><td>Progetto Pages corrente -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Worker corrente -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Quando aggiungi il binding, questi campi sono essenziali:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valore</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Seleziona il bucket creato prima</td></tr></tbody></table><p>Il nome della variabile deve essere esattamente <code>img_r2</code>. Upload, lettura ed eliminazione dei file R2 dipendono da quel nome.</p><h3 id="_3-ridistribuisci-il-progetto" tabindex="-1">3. Ridistribuisci il progetto <a class="header-anchor" href="#_3-ridistribuisci-il-progetto" aria-label="Permalink to &quot;3. Ridistribuisci il progetto&quot;">​</a></h3><p>Dopo aver salvato il binding, ridistribuisci ImgBed. In questo modo il runtime di Worker o Pages potrà accedere a <code>img_r2</code>.</p><h2 id="cosa-vedrai-in-imgbed" tabindex="-1">Cosa vedrai in ImgBed <a class="header-anchor" href="#cosa-vedrai-in-imgbed" aria-label="Permalink to &quot;Cosa vedrai in ImgBed&quot;">​</a></h2><p>Quando il binding R2 è disponibile, apri:</p><ol><li>Impostazioni di sistema.</li><li>Impostazioni di caricamento.</li><li>Il canale <code>Cloudflare R2</code>.</li></ol><p>Il sistema crea automaticamente un canale fisso:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valore fisso</th></tr></thead><tbody><tr><td>Nome canale</td><td><code>Cloudflare R2</code></td></tr><tr><td>Tipo canale</td><td><code>cfr2</code></td></tr><tr><td>Modalità di archiviazione</td><td><code>binding</code></td></tr><tr><td>Origine configurazione</td><td>Binding di ambiente</td></tr></tbody></table><p>È un canale legato al binding: non devi crearlo con Aggiungi canale e non può essere eliminato come un canale normale.</p><h2 id="campi-modificabili-nel-pannello-admin" tabindex="-1">Campi modificabili nel pannello admin <a class="header-anchor" href="#campi-modificabili-nel-pannello-admin" aria-label="Permalink to &quot;Campi modificabili nel pannello admin&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Campo</th><th>Funzione</th><th>Obbligatorio</th></tr></thead><tbody><tr><td>Abilita canale</td><td>Decide se R2 partecipa alla scelta del canale di upload.</td><td>Sì</td></tr><tr><td>Account ID</td><td>Serve solo con i limiti di quota attivi, per interrogare l&#39;uso ufficiale di R2.</td><td>Consigliato con limiti di quota</td></tr><tr><td>Nome bucket</td><td>Serve solo con i limiti di quota attivi, per interrogare l&#39;uso ufficiale di R2.</td><td>Consigliato con limiti di quota</td></tr><tr><td>Limite quota</td><td>Decide se questo canale R2 viene scelto in base alla capacità disponibile.</td><td>No</td></tr><tr><td>Soglia</td><td>Blocca nuove scritture quando l&#39;uso raggiunge la percentuale indicata.</td><td>Obbligatorio con limiti di quota</td></tr></tbody></table><p>Puoi copiare l&#39;Account ID dal pannello informazioni account della dashboard Cloudflare. Inseriscilo solo se vuoi che ImgBed controlli e applichi la quota R2.</p><p><img src="'+a+'" alt="Recupera Account ID" loading="lazy"></p><h2 id="passaggi-rapidi" tabindex="-1">Passaggi rapidi <a class="header-anchor" href="#passaggi-rapidi" aria-label="Permalink to &quot;Passaggi rapidi&quot;">​</a></h2><ol><li>Crea un bucket R2 in Cloudflare.</li><li>Apri le impostazioni Cloudflare del progetto ImgBed.</li><li>Aggiungi un binding per bucket R2.</li><li>Imposta <code>Variable name</code> su <code>img_r2</code>.</li><li>Seleziona il bucket R2 creato.</li><li>Salva il binding e ridistribuisci ImgBed.</li><li>Torna in ImgBed -&gt; Impostazioni di sistema -&gt; Impostazioni di caricamento.</li><li>Controlla che il canale <code>Cloudflare R2</code> sia presente e attivo.</li></ol><p>Se vuoi usare R2 anche nella selezione basata sulla capacità, abilita il limite quota e compila Account ID, nome bucket, limite e soglia prima di salvare.</p><p><img src="'+t+'" alt="Configura limite quota" loading="lazy"></p><h2 id="verifica" tabindex="-1">Verifica <a class="header-anchor" href="#verifica" aria-label="Permalink to &quot;Verifica&quot;">​</a></h2><ul><li>Il canale fisso <code>Cloudflare R2</code> compare nelle Impostazioni di caricamento.</li><li>La scheda del canale risulta abilitata.</li><li>Un piccolo file di prova viene caricato correttamente e il link restituito si apre.</li><li>Se aprendo un file compare <code>R2 database binding is not configured</code>, il runtime non ha ricevuto il binding <code>img_r2</code>. Controlla il nome del binding in Cloudflare e ridistribuisci il progetto.</li></ul>',37)])])}const k=o(n,[["render",c]]);export{f as __pageData,k as default};
